import base64, plistlib, sys

profile_b64 = """"""

try:
    decoded = base64.b64decode(profile_b64)
    # .mobileprovision is a DER-encoded CMS, but also contains plist data
    # Try to extract the plist portion
    start_marker = b'<?xml'
    end_marker = b'</plist>'
    start = decoded.find(start_marker)
    end = decoded.find(end_marker)
    if start >= 0 and end >= 0:
        plist_data = decoded[start:end + len(end_marker)]
        plist = plistlib.loads(plist_data)
        print(f"Name: {plist.get('Name', 'NOT FOUND')}")
        print(f"AppIDName: {plist.get('AppIDName', 'N/A')}")
        print(f"TeamName: {plist.get('TeamName', 'N/A')}")
        print(f"ExpirationDate: {plist.get('ExpirationDate', 'N/A')}")
        print(f"UUID: {plist.get('UUID', 'N/A')}")
        print(f"TeamIdentifier: {plist.get('TeamIdentifier', 'N/A')}")

        entitlements = plist.get('Entitlements', {})
        print(f"\nBundle ID: {entitlements.get('application-identifier', 'N/A')}")
    else:
        print("Could not find plist in profile")
except Exception as e:
    print(f"Error: {e}")
